\begin{tikzpicture}[scale=0.82, >=stealth]
    % parameter domain
    \begin{scope}
        \draw[->] (-0.2,0) -- (4.4,0) node[right] {\(\theta\)};
        \draw[->] (0,-0.2) -- (0,3.4) node[above] {\(z\)};

        \draw[thick] (0,0) rectangle (4,3);

        \foreach \x in {0.8,1.6,2.4,3.2}
            \draw[gray!45] (\x,0) -- (\x,3);
        \foreach \y in {0.6,1.2,1.8,2.4}
            \draw[gray!45] (0,\y) -- (4,\y);

        \node at (2,-0.65) {parameter rectangle};
        \node[left] at (0,3) {\(5\)};
        \node[below] at (4,0) {\(2\pi\)};
    \end{scope}

    % arrow
    \draw[->, thick] (4.7,1.5) -- (6.4,1.5) node[midway, above] {\(\mathbf r\)};

    % cylinder
    \begin{scope}[shift={(8,0.2)}]
        \draw[->] (-2.7,0) -- (2.9,0) node[right] {\(x\)};
        \draw[->] (0,-0.5) -- (0,3.9) node[above] {\(z\)};

        \draw[gray!50] (0,0) ellipse (1.5 and 0.38);
        \draw[thick] (-1.5,0) -- (-1.5,3);
        \draw[thick] (1.5,0) -- (1.5,3);
        \draw[thick] (0,3) ellipse (1.5 and 0.38);

        \foreach \h in {0.6,1.2,1.8,2.4}
            \draw[gray!45] (0,\h) ellipse (1.5 and 0.38);

        \foreach \x in {-1.0,0,1.0}
            \draw[gray!45] (\x,0.1) -- (\x,2.9);

        \node at (0,-0.95) {cylindrical surface};
    \end{scope}
\end{tikzpicture}

image.asymptote:
// 3-D interactive (WebGL) figure.
import graph3;
size(8cm);
currentprojection=orthographic(5,3,2.6);

real a=1.4, h=2.6;
surface cyl=surface(new triple(pair t){return (a*cos(t.x), a*sin(t.x), t.y);},(0,0),(2pi,h),40,12);
draw(cyl, rgb(0.70,0.78,0.90)+opacity(0.55), meshpen=rgb(0.45,0.5,0.65)+linewidth(0.15pt));
draw(circle((0,0,h),a,(0,0,1)), black+linewidth(0.7pt));

real th=35*pi/180, zP=1.7;
triple P=(a*cos(th), a*sin(th), zP);
triple rtheta=1.1*(-sin(th), cos(th), 0);   // d r / d theta  (around the circle)
triple rz=(0,0,1.1);                          // d r / d z      (up the axis)
triple n=1.1*(cos(th), sin(th), 0);           // r_theta x r_z  = outward radial normal

draw(P--(P+rtheta), blue+linewidth(1.4pt), Arrow3);
draw(P--(P+rz),     deepgreen+linewidth(1.4pt), Arrow3);
draw(P--(P+n),      red+linewidth(1.4pt), Arrow3);
label("$\mathbf r_\theta$", P+rtheta, NW);
label("$\mathbf r_z$", P+rz, N);
label("$\mathbf r_\theta\times\mathbf r_z$", P+n, E);
dot(P); label("$P$", P, SW);

draw(O--(2.4,0,0), gray, Arrow3); draw(O--(0,2.4,0), gray, Arrow3); draw(O--(0,0,3.2), gray, Arrow3);
label("$x$",(2.4,0,0),S); label("$y$",(0,2.4,0),E); label("$z$",(0,0,3.2),N);
